export function Block({ color_rgb, text }) { 
    const red = color_rgb.red
    const green = color_rgb.green
    const blue = color_rgb.blue
    return (
      <>
        <center>
          {text}
        </center>
        <span style={{
          backgroundColor: `rgb(${red}, ${green}, ${blue})`,
          width: 120,
          height: 120,
          float:"right",

        }}> </span>
      </>
    )
}

export function Block_with_input({ text ,is_visivle }) { 
    const [color, setColor] = useState({
        red: 0,
        green: 0,
        blue: 0,
    });
    const handleChange = (input) => e => {
        setColor({ ...color, [input]: e.target.value });
    };
    const show_input = is_visible

    return (
        <>
        <center>
            {text}
        </center>
        <span style={{
            backgroundColor: `rgb(${red}, ${green}, ${blue})`,
            width: 120,
            height: 120,
            float:"right",
            }}> </span>
        if (show_input){
            <div>
                Red
                <input
                    type="number"
                    value={color.red}
                    min="0"
                    max="255"
                    onChange={handleChange('red')}
                >
                </input>
                Green
                <input
                    type="number"
                    value={color.green}
                    min="0"
                    max="255"
                    onChange={handleChange('green')}
                >
                </input>
                Blue
                <input
                    type="number"
                    value={color.blue}
                    min="0"
                    max="255"
                    onChange={handleChange('blue')}
                >
                </input>
            </div>
        }
        </>       

    )
}
